sql:
SELECT description, country_of_origin
FROM chemical_products
WHERE country_of_origin = 'China';

SELECT COUNT(product_id) AS total_hazmat_products, description
FROM chemical_products
WHERE hazmat_indicator = 1;

SELECT COUNT(product_id) AS total_products
FROM chemical_products
WHERE country_of_origin = 'China' AND product_category = 'Pesticides';

SELECT product_category, COUNT(*) AS product_count
FROM chemical_products
GROUP BY product_category;

SELECT MAX(access_date) AS last_access_date
FROM access_logs
WHERE product_id = 1;

SELECT AVG(base_rate) AS average_base_rate, COUNT(DISTINCT country_of_origin) AS distinct_countries
FROM chemical_products
JOIN tariff_rates ON chemical_products.product_id = tariff_rates.product_id;

external_knowledge:
- "Stormy (hazardous)" refers to products with a hazmat_indicator of 1, indicating they are considered potentially harmful;
- "Calm (non-hazardous)" refers to products with a hazmat_indicator of 0, indicating they are not considered hazardous;
- Tariff rates are financial waves that affect the cost of importing or exporting products;
- Categories represent different types or classifications of chemical products, akin to different species of marine life.

